"(function () {
  const postHeight = (height, isFinal) => {
    window.webkit.messageHandlers.heightHandler.postMessage({
      height,
      type: isFinal ? "final" : "progress"
    });
  };

  const getHeight = () => document.body.scrollHeight;

  let lastHeight = 0;
  let finalTimer = null;

  // 核心：快速 final
  const scheduleFinal = () => {
    if (finalTimer) clearTimeout(finalTimer);

    finalTimer = setTimeout(() => {
      const h = getHeight();
      postHeight(h, true);
    }, 250);
  };

  const update = () => {
    const h = getHeight();

    if (h !== lastHeight) {
      lastHeight = h;
      postHeight(h, false); // 立即上报
    }

    scheduleFinal(); // 重置 final 倒计时
  };

  // ========= 各种触发 =========

  // DOM变化
  const observer = new MutationObserver(update);
  observer.observe(document.body, {
    childList: true,
    subtree: true,
    attributes: true
  });

  // 图片
  document.querySelectorAll("img").forEach(img => {
    if (!img.complete) {
      img.onload = update;
    }
  });

  // video
  document.querySelectorAll("video").forEach(video => {
    video.onloadedmetadata = update;
  });

  // resize
  window.addEventListener("resize", update);

  // 初始触发
  update();

})();"
